    def cleanup_old_logs(self, retention_days: int = 30) -> Dict:
        """Delete log indices older than the retention period."""
        cutoff_date = datetime.utcnow() - timedelta(days=retention_days)
        deleted_indices = []

        try:
            indices = self.es.indices.get(index=f"{self.LOG_INDEX_PREFIX}-*")
            for index_name in indices:
                try:
                    date_str = index_name.replace(f"{self.LOG_INDEX_PREFIX}-", "")
                    index_date = datetime.strptime(date_str, "%Y.%m.%d")
                    if index_date < cutoff_date:
                        self.es.indices.delete(index=index_name)
                        deleted_indices.append(index_name)
                        logger.info(f"Deleted old log index: {index_name}")
                except ValueError:
                    logger.warning(f"Could not parse date from index name: {index_name}")
        except Exception as e:
            logger.error(f"Error during log cleanup: {e}")
